9	
10	extension Double {
11	    static func equal(_ lhs: Double, _ rhs: Double, precise value: Int? = nil) -> Bool {
12	        guard let value = value else {
13	            return lhs == rhs
14	        }
15	        
16	        return lhs.precised(value) == rhs.precised(value)
17	    }
18	    
19	    func precised(_ value: Int = 1) -> Double {
20	        let offset = pow(10, Double(value))
21	        return (self * offset).rounded() / offset
22	    }
23	}
24	
25	extension FloatingPoint {
26	    func isNearlyEqual(to value: Self) -> Bool {
27	        return abs(self - value) <= .ulpOfOne
28	    }
29	}
30	
31	extension Array where Element == Float {
32	    
33	     func areFloatArraysNearlyEqual(_ array: [Float]) -> Bool {
34	        guard self.count == array.count else {
35	            return false
36	        }
37	        
38	        for (index, value) in self.enumerated() {
39	            if !value.isNearlyEqual(to: array[index]) {
40	                return false
41	            }
42	        }
43	        return true
44	    }
45	}
