final class DateAxisValueFormatter: AxisValueFormatter {
    func stringForValue(_ value: Double, axis: DGCharts.AxisBase?) -> String {
        value.timestampDate
    }
}

final class PrecisionAxisValueFormatter: AxisValueFormatter {

    private let radiationType: RadiationType.Level?

    init(radiationType: RadiationType.Level?) {
        self.radiationType = radiationType
    }

    func stringForValue(_ value: Double, axis: DGCharts.AxisBase?) -> String {
        guard let radiationType else {
            return value.asFloat.formattedValue()
        }
        switch radiationType {
        case .doseRate:
            let unit = UserDefaults.standard.string(forKey: "doseUnit")
                .flatMap(Settings.DoseMeasurementUnit.init(rawValue:)) ?? .sievert
            let formatted = DoseFormatted(rawValue: value.asFloat, unit: unit, mode: .dose)
            return formatted.value.formattedValue()
        case .countRate:
            let unit = UserDefaults.standard.string(forKey: "countRateUnit")
                .flatMap(Settings.CountRateMeasurementUnit.init(rawValue:)) ?? .cps
            let formatted = CountRateFormatted(rawValue: value.asFloat, unit: unit)
            return formatted.value.formattedValue()
        }
    }
}

